/**
 * Unit tests for session-rules-audit.ts
 * SessionStart hook: reads the FULL rule set from disk (CLAUDE.md +
 * .claude/rules/*.md), runs the 5 whole-set handlers, and emits their
 * combined output as SessionStart additionalContext (honored by CC).
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';
import { mockCommonBasic } from '../fixtures/mock-common.js';

// Mock all 5 whole-set handlers so audit logic is tested in isolation
const mockPriorityMap = vi.fn();
const mockDriftDetection = vi.fn();
const mockContentDedup = vi.fn();
const mockRuleConflicts = vi.fn();
const mockDebtSurfacer = vi.fn();

vi.mock('../../instructions-loaded/priority-map.js', () => ({
  priorityMap: (...args: unknown[]) => mockPriorityMap(...args),
}));
vi.mock('../../instructions-loaded/drift-detection.js', () => ({
  driftDetection: (...args: unknown[]) => mockDriftDetection(...args),
}));
vi.mock('../../instructions-loaded/content-dedup.js', () => ({
  contentDedupScanner: (...args: unknown[]) => mockContentDedup(...args),
}));
vi.mock('../../instructions-loaded/rule-conflicts.js', () => ({
  ruleConflictDetector: (...args: unknown[]) => mockRuleConflicts(...args),
}));
vi.mock('../../instructions-loaded/debt-surfacer.js', () => ({
  debtSurfacer: (...args: unknown[]) => mockDebtSurfacer(...args),
}));

// Simulated on-disk rule set
const diskFiles = new Map<string, string>();

vi.mock('node:fs', () => ({
  existsSync: (p: string) => diskFiles.has(p),
  readFileSync: (p: string) => {
    const v = diskFiles.get(p);
    if (v === undefined) throw new Error(`ENOENT: ${p}`);
    return v;
  },
  statSync: (p: string) => {
    const v = diskFiles.get(p);
    if (v === undefined) throw new Error(`ENOENT: ${p}`);
    return { size: v.length };
  },
  readdirSync: (dir: string) => {
    const prefix = `${dir}/`;
    const names = [...diskFiles.keys()]
      .filter(p => p.startsWith(prefix) && !p.slice(prefix.length).includes('/'))
      .map(p => p.slice(prefix.length));
    if (names.length === 0) throw new Error(`ENOENT: ${dir}`);
    return names;
  },
}));

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { sessionRulesAudit, collectRuleFiles } from '../../instructions-loaded/session-rules-audit.js';
import { createTestContext } from '../fixtures/test-context.js';

function makeInput(): HookInput {
  return {
    hook_event: 'SessionStart',
    tool_name: 'SessionStart',
    session_id: 'test-session',
    project_dir: '/test/project',
    tool_input: {},
  } as HookInput;
}

let testCtx: ReturnType<typeof createTestContext>;
beforeEach(() => {
  testCtx = createTestContext();
  diskFiles.clear();
  vi.clearAllMocks();
  // Default: all handlers silent
  mockPriorityMap.mockReturnValue(null);
  mockDriftDetection.mockReturnValue(null);
  mockContentDedup.mockReturnValue(null);
  mockRuleConflicts.mockReturnValue(null);
  mockDebtSurfacer.mockReturnValue(null);
});

describe('collectRuleFiles', () => {
  test('collects CLAUDE.md and .claude/rules/*.md', () => {
    diskFiles.set('/test/project/CLAUDE.md', '# project');
    diskFiles.set('/test/project/.claude/rules/a.md', 'rule a');
    diskFiles.set('/test/project/.claude/rules/b.md', 'rule b');
    diskFiles.set('/test/project/.claude/rules/notes.txt', 'not md');

    const paths = collectRuleFiles('/test/project');
    expect(paths).toEqual([
      '/test/project/CLAUDE.md',
      '/test/project/.claude/rules/a.md',
      '/test/project/.claude/rules/b.md',
    ]);
  });

  test('works without a rules dir (CLAUDE.md only)', () => {
    diskFiles.set('/test/project/CLAUDE.md', '# project');
    expect(collectRuleFiles('/test/project')).toEqual(['/test/project/CLAUDE.md']);
  });

  test('returns empty when nothing exists', () => {
    expect(collectRuleFiles('/test/project')).toEqual([]);
  });
});

describe('sessionRulesAudit', () => {
  test('silent success when no instruction files exist on disk', () => {
    const result = sessionRulesAudit(makeInput(), testCtx);
    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
    expect(mockPriorityMap).not.toHaveBeenCalled();
  });

  test('runs all 5 whole-set handlers with files + content cache from disk', () => {
    diskFiles.set('/test/project/CLAUDE.md', 'project content');
    diskFiles.set('/test/project/.claude/rules/a.md', 'rule content');

    sessionRulesAudit(makeInput(), testCtx);

    expect(mockPriorityMap).toHaveBeenCalledOnce();
    expect(mockDriftDetection).toHaveBeenCalledOnce();
    expect(mockContentDedup).toHaveBeenCalledOnce();
    expect(mockRuleConflicts).toHaveBeenCalledOnce();
    expect(mockDebtSurfacer).toHaveBeenCalledOnce();

    const [files, contents] = mockPriorityMap.mock.calls[0] as [
      Array<{ path: string; byte_size?: number }>,
      Map<string, string>,
    ];
    expect(files).toHaveLength(2);
    expect(files[0]).toEqual({ path: '/test/project/CLAUDE.md', byte_size: 15 });
    expect(contents.get('/test/project/.claude/rules/a.md')).toBe('rule content');
  });

  test('silent success when all handlers return null', () => {
    diskFiles.set('/test/project/CLAUDE.md', 'x');
    const result = sessionRulesAudit(makeInput(), testCtx);
    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  test('emits SessionStart additionalContext when handlers produce output', () => {
    diskFiles.set('/test/project/CLAUDE.md', 'x');
    mockPriorityMap.mockReturnValue('[Rule Precedence] map');
    mockDebtSurfacer.mockReturnValue('[Deferred Debt] ledger');

    const result = sessionRulesAudit(makeInput(), testCtx);
    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.hookEventName).toBe('SessionStart');
    const context = result.hookSpecificOutput?.additionalContext;
    expect(context).toContain('[Rule Precedence] map');
    expect(context).toContain('[Deferred Debt] ledger');
    expect(context).toContain('\n\n');
  });

  test('continues running remaining handlers when one throws', () => {
    diskFiles.set('/test/project/CLAUDE.md', 'x');
    mockPriorityMap.mockImplementation(() => { throw new Error('boom'); });
    mockRuleConflicts.mockReturnValue('[Rule Conflicts] found');

    const result = sessionRulesAudit(makeInput(), testCtx);
    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('[Rule Conflicts] found');
  });

  test('falls back to getProjectDir when project_dir is absent', () => {
    const input = { ...makeInput(), project_dir: undefined } as unknown as HookInput;
    // getProjectDir is mocked to /test/project via mockCommonBasic
    diskFiles.set('/test/project/CLAUDE.md', 'x');
    sessionRulesAudit(input, testCtx);
    expect(mockPriorityMap).toHaveBeenCalledOnce();
  });
});
